async function runSectionsCheck() {
  const { order, title, code } = DIAGNOSTICS_CHECKS_MAP.OUTBOUNDS;
  updateCheckStore({
    order,
    code,
    title,
    description: _("Checking, please wait"),
    state: "loading",
    items: []
  });
  const sections = await getDashboardSections();
  if (!sections.success) {
    updateCheckStore({
      order,
      code,
      title,
      description: _("Cannot receive checks result"),
      state: "error",
      items: []
    });
    throw new Error("Sections checks failed");
  }
  const items = await Promise.all(
    sections.data.map(async (section) => {
      async function getLatency() {
        if (section.withTagSelect) {
          const latencyGroup = await HarpyNetShellMethods.getClashApiGroupLatency(
            section.code
          );
          const selectedOutbound = section.outbounds.find(
            (item) => item.selected
          );
          const isUrlTest = selectedOutbound?.type === "URLTest";
          const success3 = latencyGroup.success && !latencyGroup.data.message;
          if (success3) {
            if (isUrlTest) {
              const latency2 = Object.values(latencyGroup.data).map((item) => item ? `${item}ms` : "n/a").join(" / ");
              return {
                success: true,
                latency: `[${_("Fastest")}] ${latency2}`
              };
            }
            const selectedProxyDelay = latencyGroup.data?.[selectedOutbound?.code ?? ""];
            if (selectedProxyDelay) {
              return {
                success: true,
                latency: `[${selectedOutbound?.displayName ?? ""}] ${selectedProxyDelay}ms`
              };
            }
            return {
              success: false,
              latency: `[${selectedOutbound?.displayName ?? ""}] ${_("Not responding")}`
            };
          }
          return {
            success: false,
            latency: _("Not responding")
          };
        }
        const latencyProxy = await HarpyNetShellMethods.getClashApiProxyLatency(
          section.code
        );
        const success2 = latencyProxy.success && !latencyProxy.data.message;
        if (success2) {
          return {
            success: true,
            latency: `${latencyProxy.data.delay} ms`
          };
        }
        return {
          success: false,
          latency: _("Not responding")
        };
      }
      const { latency, success } = await getLatency();
      return {
        state: success ? "success" : "error",
        key: section.displayName,
        value: latency
      };
    })
  );
  const allGood = items.every((item) => item.state === "success");
  const atLeastOneGood = items.some((item) => item.state === "success");
  const { state, description } = getMeta({ atLeastOneGood, allGood });
  updateCheckStore({
    order,
    code,
    title,
    description,
    state,
    items
  });
  if (!atLeastOneGood) {
    throw new Error("Sections checks failed");
  }
}

// ../../Desktop/HarpyNet/fe-app-harpynet/src/helpers/removeVersionPrefix.ts
function removeVersionPrefix(version) {
  return version.replace(/^v/, "");
}

// ../../Desktop/HarpyNet/fe-app-harpynet/src/harpynet/tabs/diagnostic/helpers/getHarpyNetVersionRow.ts
function isUnknownVersion(version) {
  return version === "unknown" || version === _("unknown");
}
function getHarpyNetVersionRow(diagnosticsSystemInfo) {
  const loading = diagnosticsSystemInfo.loading;
  const unknown = isUnknownVersion(diagnosticsSystemInfo.harpynet_version);
  const hasActualVersion = Boolean(diagnosticsSystemInfo.harpynet_latest_version) && !isUnknownVersion(diagnosticsSystemInfo.harpynet_latest_version);
  const version = normalizeCompiledVersion(
    diagnosticsSystemInfo.harpynet_version
  );
  const isDevVersion = version === "dev";
  if (loading || unknown || !hasActualVersion || isDevVersion) {
    return {
      key: "HarpyNet",
      value: version
    };
  }
  if (removeVersionPrefix(version) !== removeVersionPrefix(diagnosticsSystemInfo.harpynet_latest_version)) {
    return {
      key: "HarpyNet",
      value: version,
      tag: {
        label: _("Outdated"),
        kind: "warning"
      }
    };
  }
  return {
    key: "HarpyNet",
    value: version,
    tag: {
      label: _("Latest"),
      kind: "success"
    }
  };
}

